import React, { useState, useMemo } from 'react';
import styles from './PricingPage.module.css';
import { MainLayout } from '../../layouts';

const basePlans = [
  {
    key: 'free',
    name: 'Starter',
    tag: 'Free',
    monthly: 0,
    yearly: 0,
    desc: 'Perfect for individuals exploring the platform',
    features: [
      'Create profile & basic search',
      'Apply to 1 job / month',
      'Basic email notifications',
      'Community access',
    ],
  outline: true,
  },
  {
    key: 'pro',
    name: 'Professional',
    tag: 'Popular',
    monthly: 10,
    yearly: 10, // simplified pricing
    desc: 'For active interpreters & recruiters',
    features: [
      'Unlimited applications',
      'AI enhanced matching',
      'Advanced filters',
      'Priority email support',
      'Export resumes / listings',
    ],
    popular: true,
  },
  {
    key: 'team',
    name: 'Team',
    tag: 'Growth',
  monthly: 15,
  yearly: 15,
    desc: 'Collaboration tools for small teams',
    features: [
      'Up to 10 team members',
      'Team analytics dashboard',
      'Shared candidate pools',
      'Bulk messaging & scheduling',
      'Role-based permissions',
      'Priority in search results',
    ],
  },
  {
    key: 'enterprise',
    name: 'Enterprise',
    tag: 'Custom',
  monthly: 21,
  yearly: 21,
    desc: 'Large scale hiring & compliance needs',
    features: [
      'Unlimited team members',
      'Dedicated success manager',
      'Custom integrations / SSO',
      'Security & compliance reports',
      'SLAs & uptime guarantees',
      'Early feature access',
    ],
  },
];

export default function PricingPage() {
  const [billing, setBilling] = useState('monthly');
  const [openPlan, setOpenPlan] = useState(null); // plan key for payment modal
  const [purchased, setPurchased] = useState({}); // { planKey: true }
  const [paymentTab, setPaymentTab] = useState('qr');
  const [card, setCard] = useState({ number: '', name: '', exp: '', cvc: '' });
  const [processing, setProcessing] = useState(false);
  const [error, setError] = useState('');

  const plans = useMemo(() => basePlans.map(p => ({
    ...p,
    displayPrice: billing === 'monthly' ? p.monthly : p.yearly,
    yearlyDiscount: billing === 'yearly' && p.monthly && p.yearly ? Math.round((1 - (p.yearly / p.monthly)) * 100) : 0,
  })), [billing]);

  function openCheckout(planKey) {
    if (purchased[planKey]) return; // already bought
    setOpenPlan(planKey);
    setPaymentTab('qr');
    setError('');
  }

  function fakeComplete(planKey) {
    setProcessing(true);
    setError('');
    setTimeout(() => {
      setProcessing(false);
      setPurchased(prev => ({ ...prev, [planKey]: true }));
      setOpenPlan(null);
    }, 1500);
  }

  function submitCard(e) {
    e.preventDefault();
    if (!card.number || !card.name || !card.exp || !card.cvc) {
      setError('Vui lòng nhập đầy đủ thông tin thẻ');
      return;
    }
    fakeComplete(openPlan);
  }

  const currentPlan = plans.find(p => p.key === openPlan);

  return (
    <MainLayout>
      <div className={styles.pricingPageRoot}>
        <div className={styles.container}>
          <div className={styles.hero}>
            <div className={styles.badge}>Pricing Plans</div>
            <h1 className={styles.title}>Flexible pricing for every stage</h1>
            <p className={styles.subtitle}>Choose a plan that scales with you. Switch or cancel anytime. Yearly billing saves more.</p>
            <div className={styles.toggleRow}>
              <div className={styles.billingToggle}>
                <button className={billing==='monthly'?styles.active:''} onClick={()=> setBilling('monthly')}>Monthly</button>
                <button className={billing==='yearly'?styles.active:''} onClick={()=> setBilling('yearly')}>Yearly</button>
              </div>
              {billing === 'yearly' && <span className={styles.saveBadge}>SAVE UP TO 25%</span>}
            </div>
          </div>

          <div className={styles.plansGrid}>
            {plans.map(plan => {
              const isBought = purchased[plan.key];
              return (
              <div key={plan.key} className={plan.popular ? `${styles.planCard} ${styles.popular}` : styles.planCard}>
                <div className={styles.planHeader}>
                  <span className={styles.planTag}>{plan.tag}</span>
                  <h3 className={styles.planName}>{plan.name}</h3>
                  <div className={styles.priceWrap}>
                    <span className={styles.price}>{plan.displayPrice === 0 ? 'Free' : `$${plan.displayPrice}`}</span>
                    {plan.displayPrice !== 0 && <span className={styles.per}>/ {billing === 'monthly' ? 'mo' : 'mo (yr)'}</span>}
                  </div>
                  <p className={styles.desc}>{plan.desc}</p>
                </div>
                <ul className={styles.featureList}>
                  {plan.features.map(f => (
                    <li key={f} className={styles.featureItem}><i>✓</i>{f}</li>
                  ))}
                </ul>
                <button
                  disabled={isBought}
                  onClick={() => openCheckout(plan.key)}
                  className={plan.outline ? `${styles.ctaBtn} ${styles.outline}` : styles.ctaBtn}
                  style={isBought ? { opacity:.55, cursor:'default' } : undefined}
                >{isBought ? 'Purchased' : 'Get Started'}</button>
              </div>
            )})}
          </div>

          <div className={styles.comparison}>
            <h2 className={styles.comparisonTitle}>Why upgrade?</h2>
            <div className={styles.comparisonGrid}>
              <div className={styles.compBlock}>
                <span className={styles.badgeMini}>Match</span>
                <h3 className={styles.compName}>Smarter Matching</h3>
                <p className={styles.compDesc}>AI signal ranking surfaces the most relevant jobs & interpreters faster.</p>
              </div>
              <div className={styles.compBlock}>
                <span className={styles.badgeMini}>Team</span>
                <h3 className={styles.compName}>Collaboration</h3>
                <p className={styles.compDesc}>Coordinate hiring with shared pools, notes, and role-based access.</p>
              </div>
              <div className={styles.compBlock}>
                <span className={styles.badgeMini}>Scale</span>
                <h3 className={styles.compName}>Automation</h3>
                <p className={styles.compDesc}>Bulk actions, scheduling, and smart alerts reduce repetitive tasks.</p>
              </div>
              <div className={styles.compBlock}>
                <span className={styles.badgeMini}>Trust</span>
                <h3 className={styles.compName}>Security</h3>
                <p className={styles.compDesc}>Enterprise plan adds SSO, audit logs, and compliance exports.</p>
              </div>
            </div>
          </div>
        </div>
        {openPlan && currentPlan && (
          <div className={styles.paymentOverlay} onClick={()=> !processing && setOpenPlan(null)}>
            <div className={styles.paymentModal} onClick={e=> e.stopPropagation()}>
              <div className={styles.payHeader}>
                <h3>Thanh toán gói: {currentPlan.name}</h3>
                <button className={styles.closeBtn} onClick={()=> !processing && setOpenPlan(null)}>×</button>
              </div>
              <div className={styles.payTabs}>
                <button className={paymentTab==='qr'?styles.tabActive:''} onClick={()=> setPaymentTab('qr')}>QR Code</button>
                <button className={paymentTab==='card'?styles.tabActive:''} onClick={()=> setPaymentTab('card')}>Visa / Card</button>
              </div>
              <div className={styles.payBody}>
                {paymentTab === 'qr' && (
                  <div className={styles.qrSection}>
                    <div className={styles.qrBox}>
                      <div className={styles.fakeQr}></div>
                    </div>
                    <p className={styles.qrHint}>Quét mã bằng app ngân hàng hoặc ví điện tử để thanh toán số tiền: {currentPlan.displayPrice === 0 ? '0' : `$${currentPlan.displayPrice}`}</p>
                    <button disabled={processing} onClick={()=> fakeComplete(currentPlan.key)} className={styles.payConfirm}>{processing ? 'Đang xử lý...' : 'Tôi đã thanh toán'}</button>
                  </div>
                )}
                {paymentTab === 'card' && (
                  <form className={styles.cardForm} onSubmit={submitCard}>
                    <label>Số thẻ
                      <input
                        value={card.number}
                        onChange={e=> setCard(c=> ({...c, number:e.target.value}))}
                        placeholder="1111 2222 3333 4444" maxLength={19}
                      />
                    </label>
                    <label>Tên chủ thẻ
                      <input
                        value={card.name}
                        onChange={e=> setCard(c=> ({...c, name:e.target.value}))}
                        placeholder="NGUYEN VAN A"
                      />
                    </label>
                    <div className={styles.row2}>
                      <label>Hết hạn
                        <input
                          value={card.exp}
                          onChange={e=> setCard(c=> ({...c, exp:e.target.value}))}
                          placeholder="MM/YY"
                          maxLength={5}
                        />
                      </label>
                      <label>CVC
                        <input
                          value={card.cvc}
                          onChange={e=> setCard(c=> ({...c, cvc:e.target.value}))}
                          placeholder="123"
                          maxLength={4}
                        />
                      </label>
                    </div>
                    {error && <div className={styles.err}>{error}</div>}
                    <button disabled={processing} className={styles.payConfirm} type="submit">{processing ? 'Đang xử lý...' : 'Thanh toán & kích hoạt'}</button>
                  </form>
                )}
              </div>
            </div>
          </div>
        )}
      </div>
    </MainLayout>
  );
}
